7	export const ProtectedRoute = ({ children, ready = false }) => {
8	    const contextReady = use(AuthReadyContext);
9	    const isAuthenticated = useAuthStore((state) => state.isAuthenticated);
10	    const location = useLocation();
11	    const isAuthResolved = ready || contextReady;
12	
13	    if (!isAuthResolved) {
14	        return null;
15	    }
16	
17	    if (!isAuthenticated) {
18	        const returnUrl = encodeURIComponent(location.pathname);
19	
20	        return <Navigate to={`/login?returnUrl=${returnUrl}`} replace />;
21	    }
22	
23	    return children;
24	};
