12	const AUTH_ERROR_CODE = 'AUTH_1002';
13	let unauthorizedHandler = null;
14	
15	const isUnauthorized = (status, code) => status === 401 || code === AUTH_ERROR_CODE;
16	
17	const expireServerSession = () => {
18	    void axios.post('/api/v1/auth/logout', null, { withCredentials: true }).catch(() => {});
19	};
