21	export const setUnauthorizedHandler = (handler) => {
22	    unauthorizedHandler = handler;
23	};
24	
25	const handleUnauthorized = () => {
26	    // Global auth contract: any 401/AUTH_1002 response clears the local session and asks the server to expire the cookie.
27	    expireServerSession();
28	    unauthorizedHandler?.();
29	};
30	
31	axiosInstance.interceptors.response.use(
32	    (response) => response,
33	    (error) => {
34	        const status = error.response?.status;
35	        const code = error.response?.data?.code;
36	
37	        if (isUnauthorized(status, code)) {
38	            handleUnauthorized();
39	        }
40	
41	        return Promise.reject(error);
42	    }
43	);
