45	/**
46	 * @template T
47	 * @param {{data?: {success?: boolean, data?: T, message?: string} | null} | null | undefined} response
48	 * @returns {T}
49	 */
50	export const unwrapResponse = (response) => {
51	    const data = response?.data;
52	
53	    if (data === null || data === undefined) {
54	        throw new Error('요청 처리에 실패했습니다.');
55	    }
56	
57	    const isSuccess = data.success === true;
58	    const hasPayload = data.data !== null && data.data !== undefined;
59	
60	    if (!isSuccess || !hasPayload) {
61	        throw new Error(data.message ?? '요청 처리에 실패했습니다.');
62	    }
63	
64	    return data.data;
65	};
